55	const PROCESSING_FEE_GOLD = 5;
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	
58	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
59	  sword: 100,
60	  amulet: 60,
61	  staff: 80,
62	  potion: 40,
63	  rune: 25,
64	};
65	
66	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
67	const BLOCK_SIZE = 3;
68	const BLOCK_BASE_PREMIUM = 60;
69	
70	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
71	
72	const componentBasePremium = (items: Item[]): number => {
73	  const componentCounts = new Map<string, number>();
74	  for (const item of items) {
75	    if (COMPONENT_TYPES.has(item.type)) {
76	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
77	    }
78	  }
79	  let total = 0;
80	  for (const [type, count] of componentCounts) {
81	    if (count === BLOCK_SIZE) total += BLOCK_BASE_PREMIUM;
82	    else total += count * BASE_PREMIUM_BY_TYPE[type];
83	  }
84	  return total;
85	};
86	
87	const totalBasePremium = (items: Item[]): number => {
88	  const mainItemsTotal = items
89	    .filter((item) => !COMPONENT_TYPES.has(item.type))
90	    .reduce((sum, item) => sum + basePremiumOf(item), 0);
91	  return mainItemsTotal + componentBasePremium(items);
92	};
93	
94	const withFirstInsuranceSurcharge = (premium: number): number =>
95	  premium + premium * FIRST_INSURANCE_SURCHARGE_RATE;
96	
97	const quotePremium = (items: Item[]): number =>
98	  Math.ceil(withFirstInsuranceSurcharge(totalBasePremium(items)) + PROCESSING_FEE_GOLD);
99	
100	const runStep = (step: Step): StepResult => {
101	  if (step.op === "quote") return { premium: quotePremium(step.items) };
102	  return { payout: 0, remainingCap: 0 };
103	};
104	
105	export const runScenario = (scenario: Scenario): ScenarioResult => ({
106	  results: scenario.steps.map(runStep),
107	});
