const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const countByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
    new Map<string, number>(),
  );

const groupPremium = (type: string, count: number): number =>
  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUM_BY_TYPE[type];

const componentBasePremium = (items: Item[]): number => {
  const counts = countByType(items.filter(isComponent));
  return [...counts].reduce((sum, [type, count]) => sum + groupPremium(type, count), 0);
};

const totalBasePremium = (items: Item[]): number => {
  const mainItemsTotal = items
    .filter((item) => !isComponent(item))
    .reduce((sum, item) => sum + basePremiumOf(item), 0);
  return mainItemsTotal + componentBasePremium(items);
};
